export async function getCompanyBySlug(
  db: D1Database,
  slug: string
): Promise<CompanyRow | null> {
  const result = await db
    .prepare("SELECT * FROM companies WHERE slug = ?")
    .bind(slug)
    .first<CompanyRow>();
  return result ?? null;
}

export async function getCompanyById(
  db: D1Database,
  id: string
): Promise<CompanyRow | null> {
  const result = await db
    .prepare("SELECT * FROM companies WHERE id = ?")
    .bind(id)
    .first<CompanyRow>();
  return result ?? null;
}

/**
 * Insert or update a company. Returns the company id.
 * On conflict (slug), updates name and updated_at only — we never clobber
 * manually enriched fields (logo_url, website_url, etc.) with stale source data.
 */
export async function upsertCompany(
  db: D1Database,
  id: string,
  name: string,
  slug: string,
  now: number
): Promise<string> {
  await db
    .prepare(
      `INSERT INTO companies (id, name, slug, created_at, updated_at)
       VALUES (?, ?, ?, ?, ?)
       ON CONFLICT (slug) DO UPDATE SET
         name       = excluded.name,
         updated_at = excluded.updated_at`
    )
    .bind(id, name, slug, now, now)
    .run();

  // Return the canonical id (which may differ if the row already existed)
  const row = await db
    .prepare("SELECT id FROM companies WHERE slug = ?")
    .bind(slug)
    .first<{ id: string }>();
  return row!.id;
}

/**
 * Update enrichment fields for a company.
 * Only updates the provided (non-undefined) fields.
 */
export async function updateCompanyEnrichment(
  db: D1Database,
  id: string,
  fields: {
    logo_url?: string | null;
    website_url?: string | null;
    linkedin_url?: string | null;
    glassdoor_url?: string | null;
    x_url?: string | null;
    description?: string | null;
    description_enriched_at?: number | null;
  }
): Promise<void> {
  const sets: string[] = [];
  const bindings: unknown[] = [];
  const now = Math.floor(Date.now() / 1000);

  for (const [key, val] of Object.entries(fields)) {
    if (val !== undefined) {
      sets.push(`${key} = ?`);
      bindings.push(val);
    }
  }
  if (sets.length === 0) return;

  sets.push("updated_at = ?");
  bindings.push(now);
  bindings.push(id);

  await db
    .prepare(`UPDATE companies SET ${sets.join(", ")} WHERE id = ?`)
    .bind(...bindings)
    .run();
}

/** List companies that have never been enriched or have stale enrichment. */
export async function listUnenrichedCompanies(
  db: D1Database,
  staleBefore: number
): Promise<CompanyRow[]> {
  const result = await db
    .prepare(
      `SELECT * FROM companies
       WHERE description_enriched_at IS NULL
          OR description_enriched_at < ?
       LIMIT 50`
    )
    .bind(staleBefore)
    .all<CompanyRow>();
  return result.results ?? [];
}

