/**
 * Company enrichment layer.
 *
 * Problem: job ingestion sources (Greenhouse, Lever, etc.) provide company
 * name but rarely provide logo_url, website_url, linkedin_url, or other
 * brand metadata. This module addresses that gap through a separate pass.
 *
 * Approach for this phase (low-cost, no paid APIs):
 *   1. Attempt to infer website_url from a well-known pattern (company.com).
 *   2. Attempt to fetch the company's Clearbit logo via their free CDN.
 *   3. Construct LinkedIn URL from company slug as a best-effort link.
 *   4. Generate a one-sentence description using Gemini (from job context).
 *
 * These are heuristics. Each field is nullable and is never populated with
 * invented or unreliable data. The enrichment pass is designed to be re-run
 * as better data sources become available later.
 *
 * Importantly: enrichment runs asynchronously after ingestion and never
 * blocks job insertion. Failures are logged and skipped gracefully.
 */

import { extractCompanyDescription } from "./ai.ts";
import {
  listUnenrichedCompanies,
  updateCompanyEnrichment,
} from "../db/queries.ts";
import { logger } from "../utils/logger.ts";
import type { CompanyRow } from "../types.ts";

const ENRICHMENT_REFRESH_SECONDS = 7 * 24 * 60 * 60; // re-enrich every 7 days

/**
 * Build a best-effort website URL from a company slug.
 * This is a heuristic — it will work for many large companies (stripe.com,
 * airbnb.com, etc.) but will fail for companies with unusual TLDs or branding.
 * The result is stored as a candidate, not as ground truth.
 */
function inferWebsiteUrl(slug: string): string {
  return `https://www.${slug}.com`;
}

/**
 * Construct a LinkedIn company URL from a slug.
 * This is a best-effort heuristic — slug may not match the actual LinkedIn handle.
 */
function inferLinkedInUrl(slug: string): string {
  return `https://www.linkedin.com/company/${slug}`;
}

/**
 * Try to get a company logo via Clearbit's public logo API.
 * Clearbit provides a free CDN endpoint that returns a logo for known domains.
 * We verify it exists (returns 200) before storing it.
 *
 * Returns null if the domain is not recognized by Clearbit.
 */
async function fetchClearbitLogoUrl(slug: string): Promise<string | null> {
  const domain = `${slug}.com`;
  const url = `https://logo.clearbit.com/${domain}`;
  try {
    const res = await fetch(url, { method: "HEAD" });
    if (res.ok) return url;
  } catch {
    // Network failure — skip
  }
  return null;
}

/**
 * Get a sample raw job description for a company, used as context for
 * AI-powered company description generation.
 */
async function getCompanyJobContext(
  db: D1Database,
  companyId: string
): Promise<string | null> {
  const result = await db
    .prepare(
      `SELECT description_raw FROM jobs
       WHERE company_id = ? AND description_raw IS NOT NULL
       LIMIT 1`
    )
    .bind(companyId)
    .first<{ description_raw: string }>();
  return result?.description_raw ?? null;
}

/**
 * Enrich a single company record.
 * All failures are caught and logged individually so one bad company
 * does not stop the enrichment of others.
 */
async function enrichCompany(
  db: D1Database,
  company: CompanyRow,
  geminiApiKey: string
): Promise<void> {
  try {
    const now = Math.floor(Date.now() / 1000);
    const fields: Parameters<typeof updateCompanyEnrichment>[2] = {
      description_enriched_at: now,
    };

    // Only set fields that are currently null — never overwrite manually curated data
    if (!company.website_url) {
      fields.website_url = inferWebsiteUrl(company.slug);
    }

    if (!company.linkedin_url) {
      fields.linkedin_url = inferLinkedInUrl(company.slug);
    }

    if (!company.logo_url) {
      fields.logo_url = await fetchClearbitLogoUrl(company.slug);
    }

    // AI description: generate from a sample job description for context
    if (!company.description) {
      const context = await getCompanyJobContext(db, company.id);
      if (context) {
        try {
          const description = await extractCompanyDescription(
            geminiApiKey,
            company.name,
            context
          );
          if (description) fields.description = description;
        } catch (aiErr) {
          logger.warn("company_description_ai_failed", {
            company_id: company.id,
            company_name: company.name,
            error: String(aiErr),
          });
        }
      }
    }

    await updateCompanyEnrichment(db, company.id, fields);

    logger.info("company_enriched", {
      company_id: company.id,
      company_name: company.name,
      fields_updated: Object.keys(fields).filter((k) => k !== "description_enriched_at"),
    });
  } catch (err) {
    logger.error("company_enrichment_failed", {
      company_id: company.id,
      company_name: company.name,
      error: String(err),
    });
  }
}

/**
 * Run the company enrichment pass.
 * Called at the end of each ingestion cron run as a best-effort background task.
 *
 * Processes up to 50 companies per run (per listUnenrichedCompanies limit)
 * that have never been enriched or whose enrichment is older than 7 days.
 */
export async function runCompanyEnrichment(
  db: D1Database,
  geminiApiKey: string
): Promise<void> {
  const staleBefore = Math.floor(Date.now() / 1000) - ENRICHMENT_REFRESH_SECONDS;
  const companies = await listUnenrichedCompanies(db, staleBefore);

  if (companies.length === 0) {
    logger.info("company_enrichment_skipped", { reason: "no_stale_companies" });
    return;
  }

  logger.info("company_enrichment_started", { count: companies.length });

  // Enrich sequentially to avoid rate-limiting Gemini or Clearbit
  for (const company of companies) {
    await enrichCompany(db, company, geminiApiKey);
  }

  logger.info("company_enrichment_completed", { count: companies.length });
}
